     2|import { useSession } from "../hooks/useSession";
     3|
     4|export type NegotiationStep = "analise" | "oferta" | "negociacao" | "acordo";
     5|
     6|const NEGOTIATION_STEPS: { id: NegotiationStep; label: string }[] = [
     7|  { id: "analise", label: "Análise" },
     8|  { id: "oferta", label: "Oferta" },
     9|  { id: "negociacao", label: "Negociação" },
    10|  { id: "acordo", label: "Acordo" },
    11|];
    12|
    13|function stepIndex(step: NegotiationStep): number {
    14|  return NEGOTIATION_STEPS.findIndex((s) => s.id === step);
    15|}
    16|
    17|interface NegotiationProgressBarProps {
    18|  /** Current negotiation phase. Defaults to 'analise'. */
    19|  initialStep?: NegotiationStep;
    20|}
    21|
    22|/**
    23| * Horizontal stepper for the negotiation pipeline.
    24| * Tracks Análise → Oferta → Negociação → Acordo with pending / active / completed states.
    25| * Fires `step_view` and `step_complete` session events via useSession.
    26| */
    27|export function NegotiationProgressBar({
    28|  initialStep = "analise",
    29|}: NegotiationProgressBarProps) {
    30|  const { pushEvent, flushEvents } = useSession();
    31|  const [currentStep, setCurrentStep] = useState<NegotiationStep>(initialStep);
    32|  const prevStepRef = useRef<NegotiationStep>(initialStep);
    33|
    34|  useEffect(() => {
    35|    if (currentStep !== prevStepRef.current) {
    36|      const prevIdx = stepIndex(prevStepRef.current);
    37|      const currIdx = stepIndex(currentStep);
    38|
    39|      // Mark previous step complete when moving forward
    40|      if (currIdx > prevIdx) {
    41|        pushEvent({ type: "step_complete", step: prevStepRef.current });
    42|      }
    43|      // Mark new step as viewed
    44|      pushEvent({ type: "step_view", step: currentStep });
    45|
    46|      prevStepRef.current = currentStep;
    47|
    48|      // Debounced flush
    49|      const timer = setTimeout(() => flushEvents(), 500);
    50|      return () => clearTimeout(timer);
    51|    }
    52|  }, [currentStep, pushEvent, flushEvents]);
    53|
    54|  const currentIdx = stepIndex(currentStep);
    55|
    56|  return (
    57|    <div className="bg-white rounded-2xl shadow-md px-6 py-4">
    58|      <div className="flex items-center">
    59|        {NEGOTIATION_STEPS.map((step, i) => {
    60|          const isCompleted = i < currentIdx;
    61|          const isActive = i === currentIdx;
    62|          const isPending = i > currentIdx;
    63|
    64|          return (
    65|            <div key={step.id} className="flex items-center flex-1 last:flex-none">
    66|              {/* Step bubble */}
    67|              <div className="flex flex-col items-center">
    68|                <div
    69|                  className={`
    70|                    w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold border-2 transition-all
    71|                    ${
    72|                      isCompleted
    73|                        ? "bg-green-600 border-green-600 text-white"
    74|                        : isActive
    75|                          ? "bg-blue-600 border-blue-600 text-white shadow-md"
    76|                          : "bg-white border-slate-300 text-slate-400"
    77|                    }
    78|                  `}
    79|                >
    80|                  {isCompleted ? (
    81|                    <CheckIcon />
    82|                  ) : (
    83|                    <span>{i + 1}</span>
    84|                  )}
    85|                </div>
    86|                <span
    87|                  className={`
    88|                    mt-1.5 text-xs font-medium whitespace-nowrap
    89|                    ${isCompleted ? "text-green-600" : isActive ? "text-blue-600" : "text-slate-400"}
    90|                  `}
    91|                >
    92|                  {step.label}
    93|                </span>
    94|              </div>
    95|
    96|              {/* Connector line */}
    97|              {i < NEGOTIATION_STEPS.length - 1 && (
    98|                <div
    99|                  className={`
   100|                    flex-1 h-0.5 mx-2 transition-colors
   101|                    ${i < currentIdx ? "bg-green-600" : "bg-slate-200"}
   102|                  `}
   103|                />
   104|              )}
   105|            </div>
   106|          );
   107|        })}
   108|      </div>
   109|    </div>
   110|  );
   111|}
